export function NoteEditor({
  initialTitle,
  initialMarkdown,
  action,
  formTitle,
  formDescription,
  submitLabel,
  savedNotice,
  enrichment,
  generatedSummary,
  generatedTags = [],
  retryAction,
  publication
}: NoteEditorProps) {
  const [title, setTitle] = useState(initialTitle);
  const [markdown, setMarkdown] = useState(initialMarkdown);
  const [viewMode, setViewMode] = useState<NoteEditorViewMode>("source");
  const [isDesktopViewport, setIsDesktopViewport] = useState(false);
  const [editorScrollTop, setEditorScrollTop] = useState(0);
  const [cursorState, setCursorState] = useState<CursorState>(() => getCursorState(initialMarkdown, 0, 0));
  const textareaRef = useRef<HTMLTextAreaElement | null>(null);
  const selectionRef = useRef<SelectionRange>({
    end: 0,
    start: 0
  });
  const pendingSelectionRef = useRef<SelectionRange | null>(null);
  const shouldRestoreSelectionRef = useRef(false);
  const editorHintId = useId();
  const previewHeadingId = useId();
  const previewTitle = title.trim() || "Untitled note";
  const previewHtml = renderMarkdownToHtml(markdown);
  const isMobileViewport = !isDesktopViewport;
  const sourcePaneHidden = viewMode === "preview";
  const previewPaneHidden = viewMode !== "preview" && (isMobileViewport || viewMode === "source");
  const lineCount = markdown.split("\n").length;
  const wordCount = markdown.trim() ? markdown.trim().split(/\s+/).length : 0;
  const characterCount = markdown.length;
  const lineNumbers = Array.from({ length: lineCount }, (_, index) => index + 1);
  const workbenchBodyClassName = `note-editor-workbench-body note-editor-workbench-body-${viewMode}`;
  const toolbarHint = isDesktopViewport
    ? "Syntax-aware editing keeps the source visible and saves one markdown string."
    : "Edit in markdown, then switch to preview without compressing both panes onto the phone screen.";

  function runEditorAction(action: (currentMarkdown: string, selection: SelectionRange) => MarkdownEditResult) {
    const textarea = textareaRef.current;

    if (!textarea) {
      return;
    }

    const nextValue = action(markdown, {
      end: textarea.selectionEnd,
      start: textarea.selectionStart
    });

    updateMarkdown(nextValue.nextMarkdown, nextValue.nextSelection);
  }

  function syncEditorState(textarea: HTMLTextAreaElement) {
    setEditorScrollTop(textarea.scrollTop);
    selectionRef.current = {
      end: textarea.selectionEnd,
      start: textarea.selectionStart
    };
    setCursorState(getCursorState(markdown, textarea.selectionStart, textarea.selectionEnd));
  }

  function updateMarkdown(nextMarkdown: string, nextSelection?: SelectionRange) {
    setMarkdown(nextMarkdown);

    if (nextSelection) {
      selectionRef.current = nextSelection;
      pendingSelectionRef.current = nextSelection;
    }
  }

  function applyEditResult(result: MarkdownEditResult) {
    updateMarkdown(result.nextMarkdown, result.nextSelection);
  }

  function handleMarkdownChange(nextMarkdown: string) {
    setMarkdown(nextMarkdown);

    const textarea = textareaRef.current;

    if (textarea) {
      selectionRef.current = {
        end: textarea.selectionEnd,
        start: textarea.selectionStart
      };
      setCursorState(getCursorState(nextMarkdown, textarea.selectionStart, textarea.selectionEnd));
    }
  }

  function handleViewModeChange(nextMode: NoteEditorViewMode) {
    shouldRestoreSelectionRef.current = nextMode !== "preview";
    setViewMode(nextMode);
  }

  function handleEditorKeyDown(event: KeyboardEvent<HTMLTextAreaElement>) {
    const textarea = event.currentTarget;
    const selection = {
      end: textarea.selectionEnd,
      start: textarea.selectionStart
    };
    const hasShortcutModifier = event.metaKey || event.ctrlKey;
    const key = event.key.toLowerCase();

    if (hasShortcutModifier && !event.altKey && !event.shiftKey && key === "b") {
      event.preventDefault();
      applyEditResult(toggleInlineWrap(markdown, selection, "**"));
      return;
    }

    if (hasShortcutModifier && !event.altKey && !event.shiftKey && key === "i") {
      event.preventDefault();
      applyEditResult(toggleInlineWrap(markdown, selection, "*"));
      return;
    }

    if (hasShortcutModifier && !event.altKey && !event.shiftKey && key === "k") {
      event.preventDefault();
      applyEditResult(insertMarkdownLink(markdown, selection));
      return;
    }

    if (hasShortcutModifier && event.altKey && !event.shiftKey && key === "2") {
      event.preventDefault();
      applyEditResult(toggleHeading(markdown, selection, 2));
      return;
    }

    if (event.key === "Tab") {
      event.preventDefault();

      if (selection.start !== selection.end || event.shiftKey) {
        const indented = indentSelectedLines(markdown, selection, event.shiftKey);
        updateMarkdown(indented.nextMarkdown, indented.nextSelection);
        return;
      }

      const insertedIndent = applyMarkdownReplacement(markdown, selection, "  ");
      updateMarkdown(insertedIndent.nextMarkdown, insertedIndent.nextSelection);
      return;
    }

    if (event.key !== "Enter" || selection.start !== selection.end) {
      return;
    }

    const nextValue = continueMarkdownStructure(markdown, selection);

    if (nextValue) {
      event.preventDefault();
      updateMarkdown(nextValue.nextMarkdown, nextValue.nextSelection);
    }
  }

  useLayoutEffect(() => {
    const nextSelection = pendingSelectionRef.current;
    const textarea = textareaRef.current;

    if (!nextSelection || !textarea) {
      return;
    }

    pendingSelectionRef.current = null;
    textarea.focus();

function escapeHtml(value: string) {
  return value
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}

function sanitizeUrl(rawUrl: string) {
  const trimmedUrl = rawUrl.trim();

  if (!trimmedUrl) {
    return "#";
  }

  if (trimmedUrl.startsWith("/")) {
    return trimmedUrl;
  }

  try {
    const url = new URL(trimmedUrl);

    if (url.protocol === "http:" || url.protocol === "https:" || url.protocol === "mailto:") {
      return url.toString();
    }
  } catch {}

  return "#";
}

function renderInlineMarkdown(markdown: string): string {
  const pattern = /(`[^`]+`)|(\[([^\]]+)\]\(([^)]+)\))|(\*\*([^*]+)\*\*)|(\*([^*]+)\*)/g;
  let result = "";
  let cursor = 0;

  for (const match of markdown.matchAll(pattern)) {
    const matchedText = match[0];
    const matchIndex = match.index ?? 0;

    result += escapeHtml(markdown.slice(cursor, matchIndex));

    if (match[1]) {
      result += `<code>${escapeHtml(matchedText.slice(1, -1))}</code>`;
    } else if (match[2]) {
      result += `<a href="${escapeHtml(sanitizeUrl(match[4] ?? ""))}" rel="noreferrer noopener" target="_blank">${renderInlineMarkdown(match[3] ?? "")}</a>`;
    } else if (match[5]) {
      result += `<strong>${renderInlineMarkdown(match[6] ?? "")}</strong>`;
    } else if (match[7]) {
      result += `<em>${renderInlineMarkdown(match[8] ?? "")}</em>`;
    }

    cursor = matchIndex + matchedText.length;
  }

  result += escapeHtml(markdown.slice(cursor));

  return result;
}

function isUnorderedListItem(line: string) {
  return /^[-*]\s+/.test(line);
}

function isOrderedListItem(line: string) {
  return /^\d+\.\s+/.test(line);
}

function stripMarkdown(value: string) {
  return value
    .replace(/```[\s\S]*?```/g, " ")
    .replace(/`([^`]+)`/g, "$1")
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, "$1")
    .replace(/[*_>#-]/g, " ")
    .replace(/\d+\.\s+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

export function createNoteExcerpt(markdown: string, title: string, maxLength = 180) {
  const text = stripMarkdown(markdown) || title.trim();

  if (text.length <= maxLength) {
    return text;
  }

  return `${text.slice(0, maxLength).trimEnd()}...`;
}

export function renderMarkdownToHtml(markdown: string) {
  const normalizedLines = markdown.replace(/\r\n?/g, "\n").split("\n");
  const blocks: string[] = [];

  for (let index = 0; index < normalizedLines.length; ) {
    const line = normalizedLines[index];
    const trimmedLine = line.trim();

    if (!trimmedLine) {
      index += 1;
      continue;
    }

    if (trimmedLine.startsWith("```")) {
      const codeLines: string[] = [];
      index += 1;

      while (index < normalizedLines.length && !normalizedLines[index].trim().startsWith("```")) {
        codeLines.push(normalizedLines[index]);
        index += 1;
      }

      if (index < normalizedLines.length) {
        index += 1;
      }

      blocks.push(`<pre><code>${escapeHtml(codeLines.join("\n"))}</code></pre>`);
      continue;
    }

    const headingMatch = trimmedLine.match(/^(#{1,6})\s+(.*)$/);

    if (headingMatch) {
      const level = headingMatch[1].length;
      blocks.push(`<h${level}>${renderInlineMarkdown(headingMatch[2])}</h${level}>`);
      index += 1;
      continue;
    }

    if (/^---+$/.test(trimmedLine)) {
      blocks.push("<hr />");
      index += 1;
      continue;
    }

    if (trimmedLine.startsWith(">")) {
      const quoteLines: string[] = [];

      while (index < normalizedLines.length && normalizedLines[index].trim().startsWith(">")) {
        quoteLines.push(normalizedLines[index].replace(/^>\s?/, ""));
        index += 1;
      }

      const quoteContent = quoteLines.map((quoteLine) => renderInlineMarkdown(quoteLine)).join("<br />");
      blocks.push(`<blockquote><p>${quoteContent}</p></blockquote>`);
      continue;
    }

    if (isUnorderedListItem(trimmedLine)) {
      const items: string[] = [];

      while (index < normalizedLines.length && isUnorderedListItem(normalizedLines[index].trim())) {
        items.push(`<li>${renderInlineMarkdown(normalizedLines[index].trim().replace(/^[-*]\s+/, ""))}</li>`);
        index += 1;
      }

      blocks.push(`<ul>${items.join("")}</ul>`);
      continue;
    }

    if (isOrderedListItem(trimmedLine)) {
      const items: string[] = [];

      while (index < normalizedLines.length && isOrderedListItem(normalizedLines[index].trim())) {
        items.push(`<li>${renderInlineMarkdown(normalizedLines[index].trim().replace(/^\d+\.\s+/, ""))}</li>`);
        index += 1;
      }

      blocks.push(`<ol>${items.join("")}</ol>`);
      continue;
    }

    const paragraphLines: string[] = [];

    while (index < normalizedLines.length) {
      const candidate = normalizedLines[index];
      const trimmedCandidate = candidate.trim();

      if (!trimmedCandidate) {
        break;
      }

      if (
        trimmedCandidate.startsWith("```") ||
        trimmedCandidate.startsWith(">") ||
        /^---+$/.test(trimmedCandidate) ||
        /^(#{1,6})\s+/.test(trimmedCandidate) ||
        isUnorderedListItem(trimmedCandidate) ||
        isOrderedListItem(trimmedCandidate)
      ) {
        break;
      }

      paragraphLines.push(candidate);
      index += 1;
    }

    const paragraphContent = paragraphLines.map((paragraphLine) => renderInlineMarkdown(paragraphLine)).join("<br />");
    blocks.push(`<p>${paragraphContent}</p>`);
  }

  return blocks.join("\n");
}

"use server";

import { notFound, redirect } from "next/navigation";
import { revalidatePath } from "next/cache";
import { after } from "next/server";

import { runNoteEnrichment } from "@/features/notes/enrichment";
import {
  createDraftNote,
  publishNote,
  retryNoteEnrichment,
  startNoteEnrichment,
  unpublishNote,
  updateDraftNote
} from "@/features/notes/service";
import { requireOwnerSession } from "@/lib/auth/owner-session";

function getNoteInput(formData: FormData) {
  return {
    title: String(formData.get("title") ?? ""),
    markdown: String(formData.get("markdown") ?? "")
  };
}

function revalidateNotePaths(note: { id: string; slug: string }) {
  revalidatePath("/");
  revalidatePath("/app");
  revalidatePath("/app/search");
  revalidatePath("/app/tags");
  revalidatePath(`/app/notes/${note.id}/edit`);
  revalidatePath(`/notes/${note.slug}`);
}

function scheduleNoteEnrichment(note: { id: string; slug: string }, attempt: number) {
  after(async () => {
    await runNoteEnrichment(note.id, attempt);
    revalidateNotePaths(note);
  });
}

async function queueNoteEnrichment(note: { id: string; slug: string }) {
  const enrichedNote = await startNoteEnrichment(note.id);

  if (enrichedNote.enrichment.status === "pending") {
    scheduleNoteEnrichment(note, enrichedNote.enrichment.attempts);
  }

  return enrichedNote;
}

export async function createNoteAction(formData: FormData) {
  const owner = await requireOwnerSession();
  const note = await createDraftNote(owner.id, getNoteInput(formData));
  await queueNoteEnrichment(note);

  revalidateNotePaths(note);
  redirect(`/app/notes/${note.id}/edit?saved=1`);
}

export async function updateNoteAction(noteId: string, formData: FormData) {
  const owner = await requireOwnerSession();
  const note = await updateDraftNote(owner.id, noteId, getNoteInput(formData));

  if (!note) {
    notFound();
  }

  await queueNoteEnrichment(note);
  revalidateNotePaths(note);
  redirect(`/app/notes/${noteId}/edit?saved=1`);
}

export async function publishNoteAction(noteId: string) {
  const owner = await requireOwnerSession();
  const note = await publishNote(owner.id, noteId);

  if (!note) {
    notFound();
  }

  revalidateNotePaths(note);
  redirect(`/app/notes/${noteId}/edit?published=1`);
}

export async function unpublishNoteAction(noteId: string) {
  const owner = await requireOwnerSession();
