  }
};

import "server-only";

import { readFile } from "node:fs/promises";

import { mediaRepo } from "@/features/media/repo";
import { resolveMediaStoragePath } from "@/features/media/storage";
import { resolveMediaAssetAccess, type MediaAccessMode } from "@/features/media/types";

export type ReadableMediaAsset = {
  accessMode: MediaAccessMode;
  body: Uint8Array<ArrayBuffer>;
  contentType: string;
  sizeBytes: number;
};

export async function getReadableMediaAsset(assetId: string, viewerOwnerId: string | null): Promise<ReadableMediaAsset | null> {
  const asset = await mediaRepo.findAccessRecordById(assetId);

  if (!asset) {
    return null;
  }

  const accessMode = resolveMediaAssetAccess(asset, viewerOwnerId);

  if (!accessMode) {
    return null;
  }

  try {
    const body = new Uint8Array(await readFile(resolveMediaStoragePath(asset.storageKey)));

    return {
      accessMode,
      body,
      contentType: asset.contentType,
      sizeBytes: asset.sizeBytes
    };
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      return null;
    }

    throw error;
  }
}

import "server-only";

import { mkdir } from "node:fs/promises";
import path from "node:path";

import { env } from "@/lib/config/env";

function normalizeStorageKey(storageKey: string) {
  const normalizedSegments = storageKey
    .replaceAll("\\", "/")
    .split("/")
    .filter(Boolean);

  if (normalizedSegments.length === 0) {
    throw new Error("Media storage keys must include at least one path segment.");
  }

  for (const segment of normalizedSegments) {
    if (segment === "." || segment === ".." || segment.includes("\0")) {
      throw new Error(`Invalid media storage key segment: ${segment}`);
    }
  }

  return normalizedSegments.join("/");
}

export function getMediaRoot() {
  return env.mediaRoot;
}

export async function ensureMediaRoot() {
  await mkdir(getMediaRoot(), { recursive: true });
}

export function resolveMediaStoragePath(storageKey: string) {
  const root = path.resolve(getMediaRoot());
  const resolvedPath = path.resolve(root, normalizeStorageKey(storageKey));

  if (!resolvedPath.startsWith(`${root}${path.sep}`)) {
    throw new Error("Resolved media path escaped the configured media root.");
  }

  return resolvedPath;
}

