25	      return NextResponse.json(
26	        {
27	          error: "Choose an image to upload."
28	        },
29	        {
30	          status: 400
31	        }
32	      );
33	    }
34	
35	    const noteIdValue = formData.get("noteId");
36	    const noteId = typeof noteIdValue === "string" && noteIdValue.trim() ? noteIdValue.trim() : null;
37	    const uploadedImage = await uploadNoteImage({
38	      file,
39	      noteId,
40	      ownerId: session.user.id
41	    });
42	
43	    return NextResponse.json(uploadedImage, {
44	      status: 201
45	    });
46	  } catch (error) {
47	    return NextResponse.json(
48	      {
49	        error: error instanceof Error ? error.message : "Image upload failed."
50	      },
51	      {
52	        status: 400
53	      }
54	    );
