 30	  const baseName = extension ? normalizedName.slice(0, -extension.length) : normalizedName;
 31	  const sanitizedBaseName = baseName.replace(/[^a-zA-Z0-9._-]+/g, "-").replace(/-+/g, "-").replace(/^[-.]+|[-.]+$/g, "");
 32	  const finalBaseName = sanitizedBaseName || "note-image";
 33	
 34	  return `${finalBaseName}${fallbackExtension}`;
 35	}
