 48	export async function uploadNoteImage(input: { file: File; noteId: string | null; ownerId: string }) {
 49	  const extension = getNoteImageExtension(input.file.type);
 50	
 51	  if (!extension) {
 52	    throw new Error("Upload a PNG, JPG, GIF, or WEBP image.");
 53	  }
 54	
 55	  if (input.file.size === 0) {
 56	    throw new Error("Upload a non-empty image.");
 57	  }
 58	
 59	  if (input.file.size > maxNoteImageBytes) {
 60	    throw new Error("Upload an image smaller than 8 MB.");
 61	  }
 62	
 63	  if (input.noteId) {
 64	    const note = await notesRepo.findByIdForOwner(input.ownerId, input.noteId);
 65	
 66	    if (!note) {
 67	      throw new Error("The selected note could not be found.");
 68	    }
 69	  }
 70	
 71	  const assetId = randomUUID();
 72	  const fileName = sanitizeUploadFileName(input.file.name, extension);
 73	  const storageScope = input.noteId ?? "drafts";
 74	  const storageKey = `note-images/${storageScope}/${assetId}${extension}`;
 75	  const storagePath = resolveMediaStoragePath(storageKey);
 76	  const body = Buffer.from(await input.file.arrayBuffer());
 77	
 78	  await ensureMediaRoot();
 79	  await mkdir(path.dirname(storagePath), { recursive: true });
 80	  await writeFile(storagePath, body);
 81	  await mediaRepo.createNoteImageAsset({
 82	    id: assetId,
 83	    ownerId: input.ownerId,
 84	    noteId: input.noteId,
 85	    storageKey,
 86	    fileName,
 87	    contentType: input.file.type,
 88	    sizeBytes: body.byteLength
 89	  });
 90	
 91	  return {
 92	    alt: createNoteImageAltText(fileName),
 93	    assetId,
 94	    fileName,
 95	    url: getMediaAssetPath(assetId)
 96	  };
 97	}
