109	export async function getReadableMediaAsset(assetId: string, viewerOwnerId: string | null): Promise<ReadableMediaAsset | null> {
110	  const asset = await mediaRepo.findAccessRecordById(assetId);
111	
112	  if (!asset) {
113	    return null;
114	  }
115	
116	  const accessMode = resolveMediaAssetAccess(asset, viewerOwnerId);
117	
118	  if (!accessMode) {
119	    return null;
120	  }
121	
122	  try {
123	    const body = new Uint8Array(await readFile(resolveMediaStoragePath(asset.storageKey)));
124	
125	    return {
126	      accessMode,
127	      body,
128	      contentType: asset.contentType,
129	      sizeBytes: asset.sizeBytes
130	    };
131	  } catch (error) {
132	    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
133	      return null;
134	    }
135	
136	    throw error;
137	  }
138	}

