 10	function sanitizeUrl(rawUrl: string) {
 11	  const trimmedUrl = rawUrl.trim();
 12	
 13	  if (!trimmedUrl) {
 14	    return "#";
 15	  }
 16	
 17	  if (trimmedUrl.startsWith("/")) {
 18	    return trimmedUrl;
 19	  }
 20	
 21	  try {
 22	    const url = new URL(trimmedUrl);
 23	
 24	    if (url.protocol === "http:" || url.protocol === "https:" || url.protocol === "mailto:") {
 25	      return url.toString();
 26	    }
 27	  } catch {}
 28	
 29	  return "#";
 30	}
