 32	function renderInlineMarkdown(markdown: string): string {
 33	  const pattern = /(`[^`]+`)|(!\[([^\]]*)\]\(([^)]+)\))|(\[([^\]]+)\]\(([^)]+)\))|(\*\*([^*]+)\*\*)|(\*([^*]+)\*)/g;
 34	  let result = "";
 35	  let cursor = 0;
 36	
 37	  for (const match of markdown.matchAll(pattern)) {
 38	    const matchedText = match[0];
 39	    const matchIndex = match.index ?? 0;
 40	
 41	    result += escapeHtml(markdown.slice(cursor, matchIndex));
 42	
 43	    if (match[1]) {
 44	      result += `<code>${escapeHtml(matchedText.slice(1, -1))}</code>`;
 45	    } else if (match[2]) {
 46	      result += `<img alt="${escapeHtml(match[3] ?? "")}" loading="lazy" src="${escapeHtml(sanitizeUrl(match[4] ?? ""))}" />`;
 47	    } else if (match[5]) {
 48	      result += `<a href="${escapeHtml(sanitizeUrl(match[7] ?? ""))}" rel="noreferrer noopener" target="_blank">${renderInlineMarkdown(match[6] ?? "")}</a>`;
 49	    } else if (match[8]) {
 50	      result += `<strong>${renderInlineMarkdown(match[9] ?? "")}</strong>`;
 51	    } else if (match[10]) {
 52	      result += `<em>${renderInlineMarkdown(match[11] ?? "")}</em>`;
 53	    }
 54	
 55	    cursor = matchIndex + matchedText.length;
 56	  }
 57	
 58	  result += escapeHtml(markdown.slice(cursor));
 59	
 60	  return result;
 61	}
